var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"알고 있었다니......! 그럴 리가!","JPN":"わかっていただと……！　そんなバカな！","ENG":"You knew?! Impossible!","TWN":"妳是知道的……！怎麼會！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"침식파는 제대로 억제하고 있었어! 내가 네놈들이 워치를 어떻게 쓰는지 모를 줄 아나!","JPN":"侵食波はしっかり抑制していた！　貴様たちがウォッチを\\nどう使うかくらい知っている！","ENG":"I've been suppressing my Corruption ray thoroughly! Did you think I wouldn't know how your Watches work?!","TWN":"我已經完美地抑制了侵蝕波了！妳以為我不知道你們怎麼使用能量環嗎！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확실히 워치에는 아무것도 잡히지 않았죠. 그 점은 꽤 감탄했습니다.","JPN":"確かにウォッチでは何の反応も検知できなかった。\\nそれについては感心しましたね。","ENG":"Indeed, I didn't get any readings on my Watch. I was pretty impressed by that.","TWN":"能量環確實沒有感應到什麼，關於這一點我表示佩服。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 말했을 텐데. 나도 예전처럼 감상에 휘둘리는 애송이가 아니라고.","JPN":"でも言ったはずよ。もう私もかつてのように、\\n感傷に振り回される青二才ではないと。","ENG":"But like I said... I'm not the passionate emotional kid I once was.","TWN":"但我說過，我不是從前那個感情用事的小鬼了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"널 만난 후에 처음 확인한 일이 네가 말한 용병들의 소식이었지.","JPN":"あなたに会って最初に確かめたのは\\nあなたの言った傭兵たちの消息だった。","ENG":"I checked on those mercenaries you mentioned the first thing after our meeting.","TWN":"和妳見面之後，我就立刻去打探了妳說的那些傭兵們的消息。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"CARGO_SL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_SL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"공교롭게도 네가 나타나기 얼마 전에 전원 사망했다더군.","JPN":"奇しくもあなたが現れるより少し前に\\n全員死亡の憂き目に遭っていたわ。","ENG":"And what do you know... They all died shortly before you appeared.","TWN":"很不巧，他們在妳出現之前，就全部死亡了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"부검 소견서에는 쇠약사로 되어 있었는데, 식량과 물은 그대로 남아 있었어.","JPN":"司法解剖の所見書では衰弱死ということだったけれど、\\n食料と水はそのまま残っていた。","ENG":"Their autopsy report said they died of fatigue, but they hadn't touched their food and water.","TWN":"驗屍報告裡寫的是衰弱死亡，但糧食和水都完好地留了下來。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그림자에게 당한 희생자들의 전형적인 케이스지.","JPN":"シャドウにやられた犠牲者の典型的なケースよ。","ENG":"A typical case of falling victim to Shadows.","TWN":"這是被暗影殺害後，犧牲者們的典型案例。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"대장! 현실세계로 부상하겠다고 우리 애들 절반을 잡아먹었잖아!","JPN":"隊長ちゃん！　現実世界に浮上するからって、\\n子どもたちを半分も食べちゃってたじゃない！","ENG":"Commander! But you ate half our kids just so you can surface to the Normalside!","TWN":"隊長！妳不是為了躍出現實世界，吞噬了我們一半的孩子嗎！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"그런데도 부족해서 필요 없는 인간까지 건드려? 머리에 총 맞았어?","JPN":"それだけでは飽き足らず余計な人間にまで手を出したの？\\nさすがに迂闊すぎるんじゃないかしら？","ENG":"Why did you have to mess with the humans too? Did you take a bullet to the head?!","TWN":"而且還惹了沒必要惹的人類？妳腦袋是壞掉了嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"닥쳐! 내 예상보다 에너지 소모가 너무 컸단 말이다!","JPN":"黙れ！　予想よりもエネルギー消耗が大きかったからだ！","ENG":"Shut up! It required much more energy than I expected!","TWN":"閉嘴！誰知道能量消耗比我想的還要大！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"......그러게 경고했잖아. 원본을 흡수하지 않은 채로 여기를 떠나는 건 위험하다고.","JPN":"……だから警告したじゃない。オリジナルを\\n吸収しないでここを離れるのは危険だって。","ENG":"That's why I warned you. It's too dangerous to leave this place without absorbing our originals first.","TWN":"……所以我不是警告妳了嗎，沒有吸收本體就離開這裡是很危險的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"뭐가 위험하다는 거냐! 난 원본 따위 없어도 완벽한 존재야!","JPN":"危険なものか！　私はオリジナルなどなくとも完璧な存在だ！","ENG":"What's so dangerous about it? I'm already perfect without my original!","TWN":"哪裡危險了！就算沒有本體，我也是個完美的存在！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그만들 싸우지. 어차피 그 외에도 어설픈 점이 너무 많았으니까.","JPN":"言い合いしてる場合なの？\\nそもそも、他にも迂闊なところはたくさんあったわ。","ENG":"Stop bickering, you two. Besides, there were plenty of other tells that made it obvious.","TWN":"妳不用再爭了，反正除此之外，妳還有很多可疑的地方。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"류드밀라는 피만 보면 졸도하는 주제에 동료를 지키겠단 일념으로 전대장이 된 녀석이야.","JPN":"リュドミラは血を見ただけで卒倒するくせして、\\n仲間を助けたいという一念で戦隊長になった女よ。","ENG":"Lyudmila became a commander solely with her determination to save her colleagues even when she couldn't stand the sight of blood.","TWN":"盧德米拉看到血就會暈過去，是憑藉著守護同伴的意志當上戰隊隊長的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 녀석이 이런 곳에 동료들을 내버려 두고 혼자 도망쳤다고?","JPN":"そんな彼女がこんなところに仲間を放っておいて、\\n一人で逃げたですって？","ENG":"How would someone like that flee by herself when all her colleagues are down here?","TWN":"那樣的人怎麼可能把同伴丟在這種地方，一個人逃跑？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};